<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$customer=vp3_require_customer();$rows=[];$ready=false;if(vp3_db_available()){try{$stmt=vp3_db()->prepare('SELECT p.*,(SELECT COUNT(*) FROM proposal_items pi WHERE pi.proposal_id=p.id) item_count FROM proposals p WHERE p.customer_id=? ORDER BY p.created_at DESC');$stmt->execute([$customer['id']]);$rows=$stmt->fetchAll();$ready=true;}catch(Throwable){}}$pageTitle='Proposals';require VP3_ROOT.'/includes/account-header.php';?>
<div class="page-head"><div><span class="eyebrow">Scope and investment</span><h1>Proposals</h1><p class="helper">Review VP3 service scopes, pricing, deposits, terms, and acceptance status.</p></div></div><?php if(!$ready):?><div class="notice">Import the sales and creative operations migration to enable proposals.</div><?php else:?><div class="proposal-grid"><?php foreach($rows as $p):?><article class="proposal-card"><div><span class="badge <?=vp3_e($p['status'])?>"><?=vp3_e($p['status'])?></span><small><?=vp3_e($p['proposal_number'])?></small></div><h2><?=vp3_e($p['title'])?></h2><p><?=vp3_e($p['summary'])?></p><strong><?=vp3_e(vp3_money((int)$p['total_cents'],$p['currency']))?></strong><span><?=(int)$p['item_count']?> line items · Valid until <?=vp3_e($p['valid_until']?:'open')?></span><a class="button small" href="account-proposal.php?id=<?=(int)$p['id']?>">Review proposal</a></article><?php endforeach;?><?php if(!$rows):?><div class="empty-state"><h3>No proposals yet</h3><p>After discovery and brief review, VP3 can prepare a tailored project scope.</p></div><?php endif;?></div><?php endif;?>
